mapper.select:
SELECT t.transfer_id AS transferId, t.vip_benefit_id AS vipBenefitId, c.card_name AS cardName, t.from_user_id AS fromUserId, fu.nickname AS fromNickname, fu.phone AS fromPhone, t.to_user_id AS toUserId, tu.nickname AS toNickname, tu.phone AS toPhone, t.service_fee AS serviceFee, b.transfer_count AS transferCount, t.status AS status, t.refund_status AS refundStatus, t.audit_remark AS auditRemark, DATE_FORMAT(t.confirm_deadline, '%Y-%m-%d %H:%i:%s') AS confirmDeadline, DATE_FORMAT(t.created_date, '%Y-%m-%d %H:%i:%s') AS createdDate, DATE_FORMAT(t.effect_time, '%Y-%m-%d %H:%i:%s') AS effectTime FROM vip_benefit_transfer t LEFT JOIN vip_benefit b ON t.vip_benefit_id = b.vip_benefit_id LEFT JOIN vip_benefit_card c ON b.vip_card_id = c.vip_card_id LEFT JOIN user_info fu ON t.from_user_id = fu.userId LEFT JOIN user_info tu ON t.to_user_id = tu.userId
ORDER BY t.created_date DESC
LIMIT #{offset}, #{limit}
